// Time:  O(n * sqrt(r)), r = max(nums)
// Space: O(sqrt(r))

// number theory
class Solution {
public:
    int findValidSplit(vector<int>& nums) {
        const auto& factorize = [](int x) {
            vector<pair<int, int>> result;
            for (int d = 2; d * d <= x; d += (d == 2) ? 1: 2) {
                int e = 0;
                for (; x % d == 0; ++e) {
                    x /= d;
                }
                if (e) {
                    result.emplace_back(d, e);
                }
            }
            if (x > 1) {
                result.emplace_back(x, 1);
            }
            return result;
        };

        unordered_map<int, int> right;
        for (const auto& x : nums) {
            for (const auto& [p, c] : factorize(x)) {
                right[p] += c;
            }
        }
        unordered_map<int, int> left;
        for (int i = 0, cnt = 0; i < size(nums) - 1; ++i) {
            for (const auto& [p, c] : factorize(nums[i])) {
                if (!left[p]) {
                    ++cnt;
                }
                left[p] += c;
                right[p] -= c;
                if (!right[p]) {
                    --cnt;
                }
                if (!cnt) {
                    return i;
                }
            }
        }
        return -1;
    }
};

# Time:  O(n * sqrt(r)), r = max(nums)
# Space: O(sqrt(r))

import collections


# number theory
class Solution(object):
    def findValidSplit(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        def factorize(x):
            result = []
            d = 2
            while d*d <= x:
                e = 0
                while x%d == 0:
                    x //= d
                    e += 1
                if e:
                    result.append([d, e])
                d += 1 if d == 2 else 2
            if x > 1:
                result.append([x, 1])
            return result

        right = collections.Counter()
        for x in reversed(nums):
            for p, c in factorize(x):
                right[p] += c
        left = collections.Counter()
        cnt = 0
        for i in xrange(len(nums)-1):
            for p, c in factorize(nums[i]):
                if not left[p]:
                    cnt += 1
                left[p] += c
                right[p] -= c
                if not right[p]:
                    cnt -= 1
            if not cnt:
                return i
        return -1
